import json
import re

# Load review data
review_file_path = locals()['var_functions.query_db:16']
with open(review_file_path, 'r') as f:
    full_review_data = json.load(f)

# Get children's books mapping
childrens_books = locals()['var_functions.query_db:14']
childrens_book_ids = {}
for book in childrens_books:
    book_id = book['book_id']
    match = re.search(r'bookid_(\d+)', book_id)
    if match:
        numeric_id = match.group(1)
        childrens_book_ids[numeric_id] = {
            'book_id': book_id,
            'title': book['title']
        }

# Now extract relevant reviews by checking if purchase_id's numeric part exists in children's books
relevant_reviews = []
for review in full_review_data:
    purchase_id = review['purchase_id']
    match = re.search(r'purchaseid_(\d+)', purchase_id)
    if match:
        numeric_id = match.group(1)
        if numeric_id in childrens_book_ids:
            # This is a review for a children's book
            relevant_reviews.append({
                'numeric_id': numeric_id,
                'purchase_id': purchase_id,
                'rating': float(review['rating']),
                'title': review['title'],
                'review_time': review['review_time']
            })

print('__RESULT__:')
print(json.dumps({
    "total_childrens_book_reviews": len(relevant_reviews),
    "sample_relevant_reviews": relevant_reviews[:10],
    "unique_books_reviewed": len(set([r['numeric_id'] for r in relevant_reviews]))
}, indent=2))

